                            ),
                            events = listOf(
                                WinRtEventDefinition("Changed", "Sample.Foundation.WidgetChangedHandler", addMethodName = "add_Changed", removeMethodName = "remove_Changed", addMethodRowId = 6, removeMethodRowId = 7),
                            ),
                        ),
                    ),
                ),
            ),
        )

