                        ),
                        WinRtTypeDefinition(
                            namespace = "Microsoft.UI.Xaml",
                            name = "ApplicationInitializationCallback",
                            kind = WinRtTypeKind.Delegate,
                            iid = Guid("55555555-5555-5555-5555-555555555555"),
                            methods = listOf(
                                WinRtMethodDefinition(
                                    name = "Invoke",
                                    returnTypeName = "Unit",
                                    parameters = listOf(WinRtParameterDefinition("p", "Microsoft.UI.Xaml.ApplicationInitializationCallbackParams")),
                                    methodRowId = 6,
                                ),
                            ),
                        ),
                        WinRtTypeDefinition(
                            namespace = "Microsoft.UI.Xaml",
                            name = "IApplicationOverrides",
                            kind = WinRtTypeKind.Interface,
                            iid = Guid("22222222-2222-2222-2222-222222222222"),
                        ),
                        WinRtTypeDefinition(
                            namespace = "Microsoft.UI.Xaml",
                            name = "IApplicationFactory",
                            kind = WinRtTypeKind.Interface,
                            iid = Guid("33333333-3333-3333-3333-333333333333"),
                            methods = listOf(
                                WinRtMethodDefinition(
                                    name = "CreateInstance",
                                    returnTypeName = "Microsoft.UI.Xaml.Application",
                                    parameters = listOf(
                                        WinRtParameterDefinition("baseInterface", "System.Object"),
                                        WinRtParameterDefinition("innerInterface", "System.Object"),
                                    ),
                                ),
                            ),
                        ),
                        WinRtTypeDefinition(
                            namespace = "Microsoft.UI.Xaml",
                            name = "IApplicationStatics",
                            kind = WinRtTypeKind.Interface,
                            iid = Guid("44444444-4444-4444-4444-444444444444"),
                            methods = listOf(
                                WinRtMethodDefinition(
                                    name = "Start",
                                    returnTypeName = "Unit",
                                    parameters = listOf(
                                        WinRtParameterDefinition("callback", "Microsoft.UI.Xaml.ApplicationInitializationCallback"),
                                    ),
                                ),
                            ),
                        ),
                        WinRtTypeDefinition(
                            namespace = "Microsoft.UI.Xaml",
                            name = "Application",
                            kind = WinRtTypeKind.RuntimeClass,
                            defaultInterfaceName = "Microsoft.UI.Xaml.IApplication",
                            implementedInterfaces = listOf(
                                WinRtInterfaceImplementationDefinition(
                                    "Microsoft.UI.Xaml.IApplication",
                                    isDefault = true,
                                ),
                                WinRtInterfaceImplementationDefinition(
                                    "Microsoft.UI.Xaml.IApplicationOverrides",
                                    isOverridable = true,
                                ),
                            ),
                            activation = WinRtActivationShape(
                                composableFactoryInterfaceName = "Microsoft.UI.Xaml.IApplicationFactory",
                                staticInterfaceNames = listOf("Microsoft.UI.Xaml.IApplicationStatics"),
                            ),
                        ),
                    ),
                ),
            ),
        )

        val application = KotlinProjectionGenerator().generate(model)
            .single { it.relativePath.substringAfterLast('/') == "Application.kt" }
            .contents

        assertFalse(application, application.contains("WinRtWinUiResourceManagerBootstrap"))
        assertFalse(application, application.contains("_winUiResourceManagerRegistration"))
        assertTrue(application, application.contains("internal constructor(_inner: IInspectableReference, __winrtWrapper: Unit)"))
        assertTrue(application, application.contains("public constructor()"))
        val constructor = application.substringAfter("public constructor()").substringBefore("override fun equals")
        assertTrue(constructor, constructor.contains("WinRtAuthoringSupportIntrinsic.ensureInitialized()"))
        val start = application.substringAfter("public fun start(").substringBefore("override fun")
        assertFalse(start, start.contains("WinRtAuthoringSupportIntrinsic.ensureInitialized()"))
        assertFalse(start, start.contains("WinRtXamlProjectionSupportIntrinsic"))
        val startAbiCallIndex = start.indexOf("WinRtProjectionIntrinsic.callUnit(").takeIf { it >= 0 }
            ?: start.indexOf("ComVtableInvoker.invoke(").takeIf { it >= 0 }
            ?: start.indexOf("ComVtableInvoker.invokeArgs(")
        assertTrue(start, startAbiCallIndex >= 0)
        assertTrue(start, start.contains("WinRtDelegateBridge.createDelegateArgument("))
        assertTrue(start, start.contains("callback = { __args ->"))
        assertTrue(start, start.contains("__callbackAbi.abi"))
        assertFalse(start, start.contains("createReference().use"))
        assertTrue(application, application.contains("override fun exit()"))
        val exit = application.substringAfter("override fun exit()").substringBefore("override fun")
        assertFalse(exit, exit.contains("WinRtXamlProjectionSupportIntrinsic"))
        val abiCallIndex = exit.indexOf("WinRtProjectionIntrinsic.callUnit(").takeIf { it >= 0 }
            ?: exit.indexOf("ComVtableInvoker.invoke(").takeIf { it >= 0 }
            ?: exit.indexOf("ComVtableInvoker.invokeArgs(")
        assertTrue(exit, abiCallIndex >= 0)
    }

