    @Test
    fun generator_binds_runtime_event_declared_on_instantiated_generic_interface() {
        val model = WinRtMetadataModel(
            namespaces = listOf(
                WinRtNamespace(
                    name = "Windows.Foundation.Collections",
                    types = listOf(
                        WinRtTypeDefinition(
                            namespace = "Windows.Foundation.Collections",
                            name = "IMap",
