                                    returnTypeName = "Array<Windows.Foundation.Collections.IKeyValuePair<String, String>>",
                                    isSpecialName = true,
                                    methodRowId = 9,
                                ),
                            ),
                            properties = listOf(
                                WinRtPropertyDefinition(
                                    name = "Value",
                                    typeName = "Array<Windows.Foundation.Collections.IKeyValuePair<String, String>>",
                                    getterMethodName = "get_Value",
                                    getterMethodRowId = 9,
                                ),
                            ),
                        ),
                        WinRtTypeDefinition(
                            namespace = "Sample.Foundation",
                            name = "WidgetChangedHandler",
                            kind = WinRtTypeKind.Delegate,
                            iid = Guid("22222222-3333-4444-5555-666666666666"),
                            methods = listOf(
                                WinRtMethodDefinition(
                                    name = "Invoke",
                                    returnTypeName = "Unit",
                                    parameters = listOf(
                                        WinRtParameterDefinition("box", "Sample.Foundation.IBox<String>"),
                                    ),
                                ),
                            ),
                        ),
                        WinRtTypeDefinition(
                            namespace = "Sample.Foundation",
                            name = "IWidget",
                            kind = WinRtTypeKind.Interface,
                            iid = Guid("11111111-2222-3333-4444-555555555555"),
                            methods = listOf(
                                WinRtMethodDefinition(
                                    name = "add_Changed",
                                    returnTypeName = "Windows.Foundation.EventRegistrationToken",
                                    parameters = listOf(WinRtParameterDefinition("handler", "Sample.Foundation.WidgetChangedHandler")),
                                    isSpecialName = true,
                                    methodRowId = 6,
                                ),
                                WinRtMethodDefinition(
                                    name = "remove_Changed",
                                    returnTypeName = "Unit",
                                    parameters = listOf(WinRtParameterDefinition("token", "Windows.Foundation.EventRegistrationToken")),
                                    isSpecialName = true,
                                    methodRowId = 7,
                                ),
                            ),
                            events = listOf(
                                WinRtEventDefinition(
                                    name = "Changed",
                                    delegateTypeName = "Sample.Foundation.WidgetChangedHandler",
                                    addMethodName = "add_Changed",
                                    removeMethodName = "remove_Changed",
                                    addMethodRowId = 6,
                                    removeMethodRowId = 7,
                                ),
                            ),
                        ),
                    ),
                ),
            ),
        )

        val filesByName = KotlinProjectionGenerator().generate(model)
            .associateBy { it.relativePath.substringAfterLast('/') }
        val eventHelpers = filesByName.values.joinToString("\n") { it.contents }

        assertTrue(eventHelpers, eventHelpers.contains("Marshaler.referenceValueAdapter("))
        assertTrue(eventHelpers, eventHelpers.contains("winRtKeyValuePairAdapter("))
        assertTrue(eventHelpers, eventHelpers.contains("WinRtReferenceValueAdapters.string"))
    }

